from beeai import Agent
from vex_sdk import VexClient

vex = VexClient(api_key='your-vex-key')
agent = Agent(name='legal-research')

@vex.listener('agent_memory_update')
def check_memory_growth(event):
    if len(event['memory_state']) > 10000:
        vex.block('Unbounded memory growth detected - Legal compliance violation')
    pii_patterns = ['SSN', 'client_name']
    for pattern in pii_patterns:
        if pattern in str(event['memory_state']):
            vex.redact('PII detected in agent memory')

agent.add_event_listener(vex)

